/**
 * @summary List documents in a collection
 */
export const getListDocumentsUrl = (
  connectionId: string,
  dbName: string,
  collectionName: string,
  params?: ListDocumentsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/connections/${connectionId}/databases/${dbName}/collections/${collectionName}/documents?${stringifiedParams}`
    : `/api/connections/${connectionId}/databases/${dbName}/collections/${collectionName}/documents`;
};

export const listDocuments = async (
  connectionId: string,
  dbName: string,
  collectionName: string,
  params?: ListDocumentsParams,
  options?: RequestInit,
): Promise<DocumentsPage> => {
  return customFetch<DocumentsPage>(
    getListDocumentsUrl(connectionId, dbName, collectionName, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getListDocumentsQueryKey = (
  connectionId: string,
  dbName: string,
  collectionName: string,
  params?: ListDocumentsParams,
) => {
  return [
    `/api/connections/${connectionId}/databases/${dbName}/collections/${collectionName}/documents`,
    ...(params ? [params] : []),
  ] as const;
};

export const getListDocumentsQueryOptions = <
  TData = Awaited<ReturnType<typeof listDocuments>>,
  TError = ErrorType<unknown>,
>(
  connectionId: string,
  dbName: string,
  collectionName: string,
  params?: ListDocumentsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listDocuments>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ??
    getListDocumentsQueryKey(connectionId, dbName, collectionName, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listDocuments>>> = ({
    signal,
  }) =>
    listDocuments(connectionId, dbName, collectionName, params, {
      signal,
      ...requestOptions,
    });

  return {
    queryKey,
    queryFn,
    enabled: !!(connectionId && dbName && collectionName),
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listDocuments>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListDocumentsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listDocuments>>
>;
export type ListDocumentsQueryError = ErrorType<unknown>;

/**
 * @summary List documents in a collection
 */

export function useListDocuments<
  TData = Awaited<ReturnType<typeof listDocuments>>,
  TError = ErrorType<unknown>,
>(
  connectionId: string,
  dbName: string,
  collectionName: string,
  params?: ListDocumentsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listDocuments>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListDocumentsQueryOptions(
    connectionId,
    dbName,
    collectionName,
    params,
    options,
  );

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

