/**
 * @summary Analyze and infer schema for a collection
 */
export const getAnalyzeSchemaUrl = (
  connectionId: string,
  dbName: string,
  collectionName: string,
  params?: AnalyzeSchemaParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/connections/${connectionId}/databases/${dbName}/collections/${collectionName}/schema?${stringifiedParams}`
    : `/api/connections/${connectionId}/databases/${dbName}/collections/${collectionName}/schema`;
};

export const analyzeSchema = async (
  connectionId: string,
  dbName: string,
  collectionName: string,
  params?: AnalyzeSchemaParams,
  options?: RequestInit,
): Promise<SchemaAnalysis> => {
  return customFetch<SchemaAnalysis>(
    getAnalyzeSchemaUrl(connectionId, dbName, collectionName, params),
    {
      ...options,
      method: "GET",
    },
  );
};

